QueryExtension.Constraint:
( CO.ADMIN_COURT_CODE = ${param.owningCourtCode} AND
	(
		(
			CO.CO_NUMBER LIKE NVL(UPPER (${param.coNumber}), CO.CO_NUMBER )
		) 
		AND																									
		(
			CO.DEBTOR_NAME LIKE NVL(UPPER (${param.partyName}), CO.DEBTOR_NAME )
		) 
		AND
		(
			GA.ADDRESS_LINE1 LIKE NVL(UPPER (${param.address1}), GA.ADDRESS_LINE1 )
		) 
		AND						
		(
			GA.ADDRESS_LINE2 LIKE NVL(UPPER (${param.address2}), GA.ADDRESS_LINE2 )
		) 
		AND
		(
			NVL(CO.NAMED_EMPLOYER, 'v') LIKE NVL(UPPER (${param.empName}), nvl(CO.NAMED_EMPLOYER,'v') )
		)												
	)
)
